import{_ as d,o as a,c as e,ag as r}from"./chunks/framework.DEs8X8sU.js";const p=JSON.parse('{"title":"レポート","description":"","frontmatter":{"feature_id":"M-2","title":"レポート","chapter":13,"plan":["all"],"role":["owner","manager"],"audience":"店長以上","keywords":["売上","ABC分析","バスケット","回転率","客層","スタッフ評価","CSV","AI分析","予約レポート","監査ログ","エラー監視"],"related":["04-menu","06-orders","08-cashier","14-ai","15-owner","18-security","24-reservations"],"last_updated":"2026-04-19T00:00:00.000Z","maintainer":"POSLA運営"},"headers":[],"relativePath":"tenant/13-reports.md","filePath":"tenant/13-reports.md"}'),o={name:"tenant/13-reports.md"};function h(l,t,i,s,n,c){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="_13-レポート" tabindex="-1">13. レポート <a class="header-anchor" href="#_13-レポート" aria-label="Permalink to &quot;13. レポート&quot;">​</a></h1><p>管理ダッシュボードの「レポート」タブでは、売上・レジ・回転率・スタッフ評価・併売分析・<strong>予約</strong> (L-9 新機能) のレポートを閲覧できます。マネージャー以上のロールで利用できます。</p><hr><h2 id="_13-0-はじめにお読みください" tabindex="-1">13.0 はじめにお読みください <a class="header-anchor" href="#_13-0-はじめにお読みください" aria-label="Permalink to &quot;13.0 はじめにお読みください&quot;">​</a></h2><p>このページは「POSLA で取得できる全レポートを、初めて触る人でも 1 ステップずつ実行できる」ように、画面遷移・入力フィールド・実例つきで解説した完全ガイドです。</p><div class="tip custom-block"><p class="custom-block-title">この章を読む順番（おすすめ）</p><ol><li><strong>13.0.1 レポート全体マップ</strong> で、どのレポートがどの判断に使えるかを把握</li><li><strong>13.0.2 共通の前提条件</strong> で必須チェックリストを確認</li><li><strong>日次運用</strong> → 13.2 売上 → 13.3 レジ → 13.4 回転率 → 13.5 スタッフ</li><li><strong>週次・月次レビュー</strong> → 13.6 併売 + 13.7 ABC（owner）</li><li><strong>監査・障害対応</strong> → 13.8 監査ログ + 13.9 エラー監視</li><li>うまくいかなかったら → 13.Y FAQ + 13.Z トラブルシューティング</li></ol></div><h3 id="_13-0-1-レポート全体マップ" tabindex="-1">13.0.1 レポート全体マップ <a class="header-anchor" href="#_13-0-1-レポート全体マップ" aria-label="Permalink to &quot;13.0.1 レポート全体マップ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>サブタブ</th><th>用途</th><th>推奨頻度</th></tr></thead><tbody><tr><td>売上レポート</td><td>日次売上・品目ランキング・時間帯別</td><td>毎日</td></tr><tr><td>レジ分析</td><td>レジ過不足・支払方法・キャッシュログ</td><td>毎日（締め後）</td></tr><tr><td>注文履歴</td><td>個別注文の検索・調査</td><td>都度</td></tr><tr><td>回転率・客層</td><td>テーブル回転率・滞在時間・組人数</td><td>週次</td></tr><tr><td>スタッフ評価</td><td>注文数・キャンセル率・満足度・深夜操作</td><td>週次</td></tr><tr><td>併売分析</td><td>一緒に注文される品目組み合わせ</td><td>月次</td></tr><tr><td>ABC 分析 (owner)</td><td>売上構成・上位 / 下位品目</td><td>月次</td></tr><tr><td>クロス店舗 (owner)</td><td>全店舗合算・店舗ランキング</td><td>週次</td></tr><tr><td>監査ログ</td><td>誰が何をいつ操作したか</td><td>都度（不正検知）</td></tr><tr><td>エラー監視</td><td>API エラーの頻度・カテゴリ別</td><td>週次</td></tr><tr><td>予約レポート (L-9)</td><td>予約・no-show・ソース別</td><td>週次</td></tr></tbody></table><p>各 API は 13.W にまとめて記載。</p><h3 id="_13-0-2-共通の前提条件チェックリスト" tabindex="-1">13.0.2 共通の前提条件チェックリスト <a class="header-anchor" href="#_13-0-2-共通の前提条件チェックリスト" aria-label="Permalink to &quot;13.0.2 共通の前提条件チェックリスト&quot;">​</a></h3><p>各レポートを開く前に、必ず以下を確認してください。</p><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th><th>確認方法</th><th>NG 時の対応</th></tr></thead><tbody><tr><td>1</td><td><strong>manager 以上のロール</strong> でログイン</td><td>dashboard 右上のユーザー名 → ロール表示</td><td>staff の場合はオーナーに依頼</td></tr><tr><td>2</td><td><strong>店舗が選択済み</strong></td><td>画面上部の店舗セレクタにストア名が出ている</td><td>「店舗を選択してください」と出たら StoreSelector で選ぶ</td></tr><tr><td>3</td><td><strong>当該期間にデータがある</strong></td><td>売上レポートで「注文数 0」が出たら別期間</td><td>別の期間プリセットを試す</td></tr><tr><td>4</td><td><strong>営業日区切りが正しい</strong></td><td>設定タブ &gt; 営業日区切り時刻（例: 03:00）</td><td>ズレているとサマリーが昨日と今日で混ざる</td></tr><tr><td>5</td><td><strong>ブラウザは Chrome / Edge 最新版</strong></td><td>バージョン確認</td><td>Safari でグラフ崩れる場合あり</td></tr></tbody></table><h3 id="_13-0-3-プラン別機能-α-1-単一プラン" tabindex="-1">13.0.3 プラン別機能（α-1 単一プラン） <a class="header-anchor" href="#_13-0-3-プラン別機能-α-1-単一プラン" aria-label="Permalink to &quot;13.0.3 プラン別機能（α-1 単一プラン）&quot;">​</a></h3><p><strong>2026-04-09 以降、全レポート（売上・回転率・スタッフ評価・併売分析・ABC・監査ログ・エラー監視）は全契約者に標準提供</strong>されます。以前の standard / pro / enterprise 区別は廃止。実装: <code>api/lib/auth.php</code> L238-246 の <code>check_plan_feature()</code> が <code>hq_menu_broadcast</code> 以外すべて <code>true</code> を返すため、UI 側の <code>plan-hidden</code> クラスも発火しません。</p><h3 id="_13-0-4-章マップ" tabindex="-1">13.0.4 章マップ <a class="header-anchor" href="#_13-0-4-章マップ" aria-label="Permalink to &quot;13.0.4 章マップ&quot;">​</a></h3><p>13.1 共通操作 / 13.2 売上 / 13.3 レジ / 13.4 注文履歴 / 13.5 回転率・客層 / 13.6 スタッフ評価 / 13.7 併売 / 13.8 ABC (owner) / 13.9 クロス店舗 (owner) / 13.10 監査ログ / 13.11 エラー監視 / 13.12 予約 / 13.Y FAQ 25 件 / 13.Z トラブル / 13.W データベース</p><hr><h2 id="_13-1-共通操作" tabindex="-1">13.1 共通操作 <a class="header-anchor" href="#_13-1-共通操作" aria-label="Permalink to &quot;13.1 共通操作&quot;">​</a></h2><h3 id="_13-1-1-期間プリセットボタン" tabindex="-1">13.1.1 期間プリセットボタン <a class="header-anchor" href="#_13-1-1-期間プリセットボタン" aria-label="Permalink to &quot;13.1.1 期間プリセットボタン&quot;">​</a></h3><p>全レポートの上部に同じプリセット 4 ボタンが並びます。クリックすると <code>from</code> / <code>to</code> の日付フィールドが即座に書き換わり、自動で再読込されます。</p><table tabindex="0"><thead><tr><th>プリセット</th><th>設定される from</th><th>設定される to</th><th>用途</th></tr></thead><tbody><tr><td>今日</td><td>当日 (営業日基準)</td><td>当日</td><td>営業中のリアルタイム確認</td></tr><tr><td>昨日</td><td>前営業日</td><td>前営業日</td><td>締め後の振り返り</td></tr><tr><td>今週</td><td>月曜日</td><td>当日</td><td>週次レビュー</td></tr><tr><td>今月</td><td>1 日</td><td>当日</td><td>月次レビュー</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">営業日基準</p><p>「営業日区切り時刻」（例: 03:00）を考慮。深夜営業店では「2026-04-19 02:30」の注文は 4/18 の売上として集計（実装: <code>api/lib/business-day.php</code>）。</p></div><h3 id="_13-1-2-カスタム期間-csv-店舗フィルタ" tabindex="-1">13.1.2 カスタム期間 / CSV / 店舗フィルタ <a class="header-anchor" href="#_13-1-2-カスタム期間-csv-店舗フィルタ" aria-label="Permalink to &quot;13.1.2 カスタム期間 / CSV / 店舗フィルタ&quot;">​</a></h3><ul><li><strong>カスタム期間</strong>: from / to 日付ピッカー → 「表示」ボタン（6 ヶ月超は遅延注意）</li><li><strong>CSV エクスポート</strong>: 各 API に <code>?format=csv</code> を付与。文字コード UTF-8 with BOM（Excel 自動認識）</li><li><strong>店舗フィルタ (owner)</strong>: ABC・クロス店舗レポートに「全店舗合算 / 個別店舗」ドロップダウン。manager は自店舗固定</li></ul><h3 id="_13-1-5-画面遷移" tabindex="-1">13.1.5 画面遷移 <a class="header-anchor" href="#_13-1-5-画面遷移" aria-label="Permalink to &quot;13.1.5 画面遷移&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[dashboard] → 「レポート」タブ → サブタブ → プリセット + 日付 → 「表示」</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[サマリーカード] + [詳細テーブル / バーチャート]</span></span></code></pre></div><hr><h2 id="_13-2-売上レポート" tabindex="-1">13.2 売上レポート <a class="header-anchor" href="#_13-2-売上レポート" aria-label="Permalink to &quot;13.2 売上レポート&quot;">​</a></h2><p>「レポート」タブ → 「売上レポート」サブタブ</p><h3 id="_13-2-1-操作前のチェックリスト" tabindex="-1">13.2.1 操作前のチェックリスト <a class="header-anchor" href="#_13-2-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.2.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>店舗が選択されている</td></tr><tr><td>2</td><td>期間に少なくとも 1 件の <code>paid</code> ステータスの注文がある</td></tr><tr><td>3</td><td>レジ締めが完了している（締め前は <code>paid_at</code> が未設定の注文が含まれる）</td></tr></tbody></table><h3 id="_13-2-2-操作手順-クリック単位" tabindex="-1">13.2.2 操作手順（クリック単位） <a class="header-anchor" href="#_13-2-2-操作手順-クリック単位" aria-label="Permalink to &quot;13.2.2 操作手順（クリック単位）&quot;">​</a></h3><ol><li>dashboard.html → 上部タブ <strong>「レポート」</strong> をクリック</li><li>サブタブ <strong>「売上レポート」</strong> をクリック</li><li>既定で「今日」のデータが表示される</li><li>期間を変えたい場合はプリセットボタン or 日付ピッカー</li><li><strong>「表示」</strong> ボタンをクリック（プリセット選択時は自動再読込）</li><li>1〜3 秒後にデータが描画される</li></ol><h3 id="_13-2-3-表示されるセクション" tabindex="-1">13.2.3 表示されるセクション <a class="header-anchor" href="#_13-2-3-表示されるセクション" aria-label="Permalink to &quot;13.2.3 表示されるセクション&quot;">​</a></h3><h4 id="_13-2-3-1-サマリーカード" tabindex="-1">13.2.3.1 サマリーカード <a class="header-anchor" href="#_13-2-3-1-サマリーカード" aria-label="Permalink to &quot;13.2.3.1 サマリーカード&quot;">​</a></h4><table tabindex="0"><thead><tr><th>カード</th><th>値</th><th>計算式</th></tr></thead><tbody><tr><td>注文数</td><td>期間内の <code>status=&#39;paid&#39;</code> 注文件数</td><td><code>COUNT(*)</code></td></tr><tr><td>売上合計</td><td>期間内の総売上</td><td><code>SUM(total_amount)</code></td></tr><tr><td>平均注文額</td><td>売上 ÷ 注文件数</td><td><code>AVG(total_amount)</code></td></tr></tbody></table><h4 id="_13-2-3-2-提供時間分析-service-time-analysis" tabindex="-1">13.2.3.2 提供時間分析（service time analysis） <a class="header-anchor" href="#_13-2-3-2-提供時間分析-service-time-analysis" aria-label="Permalink to &quot;13.2.3.2 提供時間分析（service time analysis）&quot;">​</a></h4><p>注文受付（<code>created_at</code>）から提供（<code>served_at</code> または <code>ready_at</code>）までの秒数。</p><table tabindex="0"><thead><tr><th>カード</th><th>説明</th></tr></thead><tbody><tr><td>平均</td><td>全注文の平均提供時間</td></tr><tr><td>中央値</td><td>データの中央 50% の境界値</td></tr><tr><td>最短</td><td>最も早かった提供時間</td></tr><tr><td>最長</td><td>最も遅かった提供時間</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">平均と中央値が乖離している場合</p><p>特定の遅い注文（厨房トラブル等）が平均値を引き上げています。中央値で実態を把握してください。</p></div><h4 id="_13-2-3-3-品目ランキング-売上順-top-20" tabindex="-1">13.2.3.3 品目ランキング（売上順 TOP 20） <a class="header-anchor" href="#_13-2-3-3-品目ランキング-売上順-top-20" aria-label="Permalink to &quot;13.2.3.3 品目ランキング（売上順 TOP 20）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>順位</td><td>1〜3 は 🥇🥈🥉、4 位以降は数字</td></tr><tr><td>品名</td><td>メニュー名</td></tr><tr><td>数量</td><td>期間内の販売数</td></tr><tr><td>売上</td><td>その品目の合計売上</td></tr></tbody></table><h4 id="_13-2-3-4-時間帯別売上-バーチャート" tabindex="-1">13.2.3.4 時間帯別売上（バーチャート） <a class="header-anchor" href="#_13-2-3-4-時間帯別売上-バーチャート" aria-label="Permalink to &quot;13.2.3.4 時間帯別売上（バーチャート）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>時間帯</td><td>0時〜23時</td></tr><tr><td>注文数</td><td>その時間帯の注文件数</td></tr><tr><td>売上</td><td>その時間帯の売上金額</td></tr></tbody></table><p>棒の長さは「最大売上の時間帯 = 100%」で正規化。</p><h3 id="_13-2-4-入力フィールドの詳細表" tabindex="-1">13.2.4 入力フィールドの詳細表 <a class="header-anchor" href="#_13-2-4-入力フィールドの詳細表" aria-label="Permalink to &quot;13.2.4 入力フィールドの詳細表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>入力例</th><th>必須</th><th>形式</th><th>補足</th></tr></thead><tbody><tr><td>1</td><td>from</td><td><code>2026-04-01</code></td><td>✅</td><td>YYYY-MM-DD</td><td>営業日基準</td></tr><tr><td>2</td><td>to</td><td><code>2026-04-19</code></td><td>✅</td><td>YYYY-MM-DD</td><td>from &lt;= to</td></tr><tr><td>3</td><td>プリセット</td><td>today/yesterday/week/month</td><td>任意</td><td>クリック</td><td>from/to を上書き</td></tr></tbody></table><h3 id="_13-2-5-実例-1-日サマリー" tabindex="-1">13.2.5 実例（1 日サマリー） <a class="header-anchor" href="#_13-2-5-実例-1-日サマリー" aria-label="Permalink to &quot;13.2.5 実例（1 日サマリー）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>注文 87 / 売上 ¥184,200 / 平均 ¥2,117</span></span>
<span class="line"><span>提供時間 平均 11:32 / 中央値 9:12 / 目標 10 分超過</span></span>
<span class="line"><span>1 位 焼き魚定食 28 食 / ピーク 12 時 24 件</span></span></code></pre></div><p>→ 12 時集中は厨房ボトルネック。14 章「需要予測」で人員追加を検討。</p><hr><h2 id="_13-3-レジ分析" tabindex="-1">13.3 レジ分析 <a class="header-anchor" href="#_13-3-レジ分析" aria-label="Permalink to &quot;13.3 レジ分析&quot;">​</a></h2><p>「レポート」タブ → 「レジ分析」サブタブ</p><h3 id="_13-3-1-操作前のチェックリスト" tabindex="-1">13.3.1 操作前のチェックリスト <a class="header-anchor" href="#_13-3-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.3.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>当日のレジ開け (<code>cash_log.type=&#39;open&#39;</code>) が記録されている</td></tr><tr><td>2</td><td>(締め後の確認なら) レジ締め (<code>type=&#39;close&#39;</code>) が記録されている</td></tr><tr><td>3</td><td>manager 以上のロール</td></tr></tbody></table><h3 id="_13-3-2-操作手順" tabindex="-1">13.3.2 操作手順 <a class="header-anchor" href="#_13-3-2-操作手順" aria-label="Permalink to &quot;13.3.2 操作手順&quot;">​</a></h3><ol><li>dashboard.html → <strong>「レポート」</strong> タブ</li><li>サブタブ <strong>「レジ分析」</strong> をクリック</li><li>既定で「今日」が表示される</li><li>プリセットまたは日付ピッカーで期間を変更</li><li><strong>「表示」</strong> ボタン</li></ol><h3 id="_13-3-3-サマリーカード" tabindex="-1">13.3.3 サマリーカード <a class="header-anchor" href="#_13-3-3-サマリーカード" aria-label="Permalink to &quot;13.3.3 サマリーカード&quot;">​</a></h3><table tabindex="0"><thead><tr><th>カード</th><th>説明</th><th>計算式</th></tr></thead><tbody><tr><td>レジ開け</td><td>営業開始時のつり銭準備金</td><td><code>cash_log</code> 最新の <code>type=&#39;open&#39;</code></td></tr><tr><td>現金売上</td><td>現金決済の合計</td><td><code>payments WHERE method=&#39;cash&#39;</code></td></tr><tr><td>入金</td><td>営業中の <code>cash_in</code> 合計</td><td>—</td></tr><tr><td>出金</td><td>営業中の <code>cash_out</code> 合計</td><td>—</td></tr><tr><td>予想残高</td><td>開始 + 現金売上 + 入金 − 出金</td><td>自動算出</td></tr><tr><td>レジ締め</td><td>営業終了時の実際残高</td><td><code>type=&#39;close&#39;</code> の amount</td></tr><tr><td>過不足</td><td>レジ締め − 予想残高</td><td>自動算出</td></tr></tbody></table><h4 id="過不足の色分け" tabindex="-1">過不足の色分け <a class="header-anchor" href="#過不足の色分け" aria-label="Permalink to &quot;過不足の色分け&quot;">​</a></h4><table tabindex="0"><thead><tr><th>状態</th><th>色</th><th>意味</th><th>対応</th></tr></thead><tbody><tr><td>マイナス（不足）</td><td>赤 (#e53935)</td><td>実際残高 &lt; 予想残高</td><td>釣り銭ミス・抜き取り疑惑 → 監査ログ確認</td></tr><tr><td>ゼロ</td><td>黒</td><td>完全一致</td><td>正常</td></tr><tr><td>プラス（過剰）</td><td>青 (#1565c0)</td><td>実際残高 &gt; 予想残高</td><td>入金ログ漏れ・釣り銭返し忘れ</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">500 円以上の過不足</p><p>スタッフ評価レポート (13.6) で行ハイライトされます。3 日連続で発生したら次の対策を検討:</p><ul><li>レジ担当 PIN（CB1d、18 章 18.Z 参照）の運用徹底</li><li>レジカメラ設置</li><li>スタッフ研修</li></ul></div><h3 id="_13-3-4-支払方法別内訳" tabindex="-1">13.3.4 支払方法別内訳 <a class="header-anchor" href="#_13-3-4-支払方法別内訳" aria-label="Permalink to &quot;13.3.4 支払方法別内訳&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>方法</td><td>現金 / カード / QR (<code>payment_method</code> ENUM)</td></tr><tr><td>件数</td><td>決済件数</td></tr><tr><td>金額</td><td>合計金額</td></tr></tbody></table><h3 id="_13-3-5-キャッシュログ詳細-時系列" tabindex="-1">13.3.5 キャッシュログ詳細（時系列） <a class="header-anchor" href="#_13-3-5-キャッシュログ詳細-時系列" aria-label="Permalink to &quot;13.3.5 キャッシュログ詳細（時系列）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>時刻</td><td>操作日時</td></tr><tr><td>種別</td><td>レジ開け / 締め / 入金 / 出金 / 現金売上</td></tr><tr><td>担当者</td><td>スタッフ名（PIN 認証されたユーザー）</td></tr><tr><td>金額</td><td>操作金額</td></tr><tr><td>メモ</td><td>自由入力（出金理由など）</td></tr></tbody></table><h3 id="_13-3-6-実例-1-日のレジ" tabindex="-1">13.3.6 実例（1 日のレジ） <a class="header-anchor" href="#_13-3-6-実例-1-日のレジ" aria-label="Permalink to &quot;13.3.6 実例（1 日のレジ）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>開け ¥30,000 / 現金売上 ¥86,400 / 出金 ¥1,200 / 予想 ¥115,200 / 締め ¥114,800</span></span>
<span class="line"><span>過不足 -¥400 (赤)</span></span></code></pre></div><p>→ 18 章「PIN 監視」+ 監査ログで時間帯特定。</p><hr><h2 id="_13-4-注文履歴" tabindex="-1">13.4 注文履歴 <a class="header-anchor" href="#_13-4-注文履歴" aria-label="Permalink to &quot;13.4 注文履歴&quot;">​</a></h2><p>「レポート」タブ → 「注文履歴」サブタブ</p><h3 id="_13-4-1-用途" tabindex="-1">13.4.1 用途 <a class="header-anchor" href="#_13-4-1-用途" aria-label="Permalink to &quot;13.4.1 用途&quot;">​</a></h3><ul><li>お客様クレーム時の個別注文調査</li><li>「11:42 のテーブル A の注文内容」を特定</li><li>キャンセル注文の詳細確認</li></ul><h3 id="_13-4-2-操作前のチェックリスト" tabindex="-1">13.4.2 操作前のチェックリスト <a class="header-anchor" href="#_13-4-2-操作前のチェックリスト" aria-label="Permalink to &quot;13.4.2 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>検索したい時間帯 / テーブル / 品名のいずれかが分かっている</td></tr><tr><td>2</td><td>manager 以上</td></tr></tbody></table><h3 id="_13-4-3-操作手順" tabindex="-1">13.4.3 操作手順 <a class="header-anchor" href="#_13-4-3-操作手順" aria-label="Permalink to &quot;13.4.3 操作手順&quot;">​</a></h3><ol><li>dashboard.html → <strong>「レポート」</strong> → <strong>「注文履歴」</strong></li><li>プリセットまたは日付ピッカー</li><li><strong>ステータス</strong> ドロップダウンで絞り込み（任意）</li><li><strong>検索ボックス</strong> に品名を入力（任意、JSON LIKE 検索）</li><li><strong>「表示」</strong> ボタン</li><li>1〜3 秒で 20 件ずつページネーション表示</li></ol><h3 id="_13-4-4-入力フィールドの詳細表" tabindex="-1">13.4.4 入力フィールドの詳細表 <a class="header-anchor" href="#_13-4-4-入力フィールドの詳細表" aria-label="Permalink to &quot;13.4.4 入力フィールドの詳細表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>入力例</th><th>必須</th><th>形式</th><th>補足</th></tr></thead><tbody><tr><td>1</td><td>from</td><td><code>2026-04-15</code></td><td>✅</td><td>YYYY-MM-DD</td><td></td></tr><tr><td>2</td><td>to</td><td><code>2026-04-15</code></td><td>✅</td><td>YYYY-MM-DD</td><td></td></tr><tr><td>3</td><td>status</td><td><code>paid</code> / <code>cancelled</code> 等</td><td>任意</td><td>ENUM</td><td>6 値から選択</td></tr><tr><td>4</td><td>q (検索)</td><td><code>焼き魚</code></td><td>任意</td><td>部分一致</td><td>items JSON LIKE</td></tr><tr><td>5</td><td>page</td><td><code>1</code></td><td>任意</td><td>整数</td><td>既定 1</td></tr><tr><td>6</td><td>limit</td><td><code>20</code></td><td>任意</td><td>10-100</td><td>既定 20、最大 100</td></tr></tbody></table><h3 id="_13-4-5-ステータスの種類" tabindex="-1">13.4.5 ステータスの種類 <a class="header-anchor" href="#_13-4-5-ステータスの種類" aria-label="Permalink to &quot;13.4.5 ステータスの種類&quot;">​</a></h3><table tabindex="0"><thead><tr><th>status</th><th>表示</th><th>意味</th></tr></thead><tbody><tr><td><code>pending</code></td><td>受付</td><td>KDS 投入直後</td></tr><tr><td><code>preparing</code></td><td>調理中</td><td>厨房着手</td></tr><tr><td><code>ready</code></td><td>提供待ち</td><td>完成・配膳待ち</td></tr><tr><td><code>served</code></td><td>提供済み</td><td>お客様に渡した</td></tr><tr><td><code>paid</code></td><td>会計済み</td><td>集計対象</td></tr><tr><td><code>cancelled</code></td><td>キャンセル</td><td>売上から除外</td></tr></tbody></table><h3 id="_13-4-6-表示テーブル列" tabindex="-1">13.4.6 表示テーブル列 <a class="header-anchor" href="#_13-4-6-表示テーブル列" aria-label="Permalink to &quot;13.4.6 表示テーブル列&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>時刻</td><td><code>created_at</code></td></tr><tr><td>テーブル</td><td><code>table_code</code></td></tr><tr><td>品目</td><td><code>name × qty</code> のカンマ区切り</td></tr><tr><td>削除品</td><td><code>removed_items</code>（取り消された品目、赤色取り消し線）</td></tr><tr><td>金額</td><td><code>total_amount</code></td></tr><tr><td>提供時間</td><td><code>served_at - created_at</code></td></tr><tr><td>ステータス</td><td>バッジ表示</td></tr></tbody></table><h3 id="_13-4-7-実例-クレーム調査" tabindex="-1">13.4.7 実例（クレーム調査） <a class="header-anchor" href="#_13-4-7-実例-クレーム調査" aria-label="Permalink to &quot;13.4.7 実例（クレーム調査）&quot;">​</a></h3><p>「12:00 / C-3 / 焼き魚」→ 検索ボックス「焼き魚」+ 今日 → 結果「12:03 / C-3 / ¥1,100 / 提供時間 28 分」→ 調理時間異常を 13.5 と比較、必要なら 13.10 監査ログで status 遷移確認。</p><hr><h2 id="_13-5-回転率・客層レポート" tabindex="-1">13.5 回転率・客層レポート <a class="header-anchor" href="#_13-5-回転率・客層レポート" aria-label="Permalink to &quot;13.5 回転率・客層レポート&quot;">​</a></h2><p>「レポート」タブ → 「回転率・客層」サブタブ（実装: <code>turnover-report.js</code>）</p><h3 id="_13-5-1-操作前のチェックリスト" tabindex="-1">13.5.1 操作前のチェックリスト <a class="header-anchor" href="#_13-5-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.5.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>テーブルセッション機能（QR 入店）が有効</td></tr><tr><td>2</td><td>当該期間に <code>table_sessions</code> レコードがある</td></tr><tr><td>3</td><td>manager 以上</td></tr></tbody></table><h3 id="_13-5-2-操作手順" tabindex="-1">13.5.2 操作手順 <a class="header-anchor" href="#_13-5-2-操作手順" aria-label="Permalink to &quot;13.5.2 操作手順&quot;">​</a></h3><ol><li><strong>「レポート」</strong> → <strong>「回転率・客層」</strong> サブタブ</li><li>プリセット（既定: 今日）</li><li><strong>「表示」</strong> ボタン</li></ol><h3 id="_13-5-3-表示セクション" tabindex="-1">13.5.3 表示セクション <a class="header-anchor" href="#_13-5-3-表示セクション" aria-label="Permalink to &quot;13.5.3 表示セクション&quot;">​</a></h3><h4 id="サマリー-4-カード" tabindex="-1">サマリー（4 カード） <a class="header-anchor" href="#サマリー-4-カード" aria-label="Permalink to &quot;サマリー（4 カード）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>カード</th><th>説明</th></tr></thead><tbody><tr><td>平均滞在</td><td>全セッションの平均滞在分</td></tr><tr><td>平均回転</td><td>テーブルあたりの平均利用回数</td></tr><tr><td>ピーク時間帯</td><td>最も組数が多い時間帯</td></tr><tr><td>調理超過率</td><td>目標調理時間を超えた品目の割合（≥20% で赤）</td></tr></tbody></table><h4 id="テーブル別回転率" tabindex="-1">テーブル別回転率 <a class="header-anchor" href="#テーブル別回転率" aria-label="Permalink to &quot;テーブル別回転率&quot;">​</a></h4><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>テーブル</td><td>テーブルコード</td></tr><tr><td>回転数</td><td>利用回数</td></tr><tr><td>平均滞在</td><td>分単位</td></tr><tr><td>合計客数</td><td>—</td></tr></tbody></table><h4 id="ランチ-ディナー比較" tabindex="-1">ランチ / ディナー比較 <a class="header-anchor" href="#ランチ-ディナー比較" aria-label="Permalink to &quot;ランチ / ディナー比較&quot;">​</a></h4><table tabindex="0"><thead><tr><th>時間帯</th><th>範囲</th></tr></thead><tbody><tr><td>ランチ</td><td>10:00〜15:00</td></tr><tr><td>ディナー</td><td>17:00〜23:00</td></tr><tr><td>その他</td><td>上記以外</td></tr></tbody></table><p>各時間帯について：組数、客数、平均滞在、売上</p><h4 id="時間帯別効率-棒グラフ" tabindex="-1">時間帯別効率（棒グラフ） <a class="header-anchor" href="#時間帯別効率-棒グラフ" aria-label="Permalink to &quot;時間帯別効率（棒グラフ）&quot;">​</a></h4><p>1 時間ごとの組数・客数・売上・平均滞在</p><h4 id="調理時間分析" tabindex="-1">調理時間分析 <a class="header-anchor" href="#調理時間分析" aria-label="Permalink to &quot;調理時間分析&quot;">​</a></h4><ul><li><strong>品目別</strong>: 各品目の平均・最大調理秒数、超過時はオレンジ</li><li><strong>全体サマリー</strong>: 平均、中央値、目標時間（店舗設定）、超過率</li></ul><h4 id="組人数別分析" tabindex="-1">組人数別分析 <a class="header-anchor" href="#組人数別分析" aria-label="Permalink to &quot;組人数別分析&quot;">​</a></h4><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>人数帯</td><td>1名 / 2名 / 3名 / 4名以上</td></tr><tr><td>組数</td><td>—</td></tr><tr><td>客数</td><td>—</td></tr><tr><td>組平均単価</td><td>—</td></tr><tr><td>客単価</td><td>—</td></tr></tbody></table><h4 id="価格帯別注文分布-バーチャート" tabindex="-1">価格帯別注文分布（バーチャート） <a class="header-anchor" href="#価格帯別注文分布-バーチャート" aria-label="Permalink to &quot;価格帯別注文分布（バーチャート）&quot;">​</a></h4><p>注文金額を価格帯で 5-10 段階に分けて表示。</p><h4 id="時間帯別客層" tabindex="-1">時間帯別客層 <a class="header-anchor" href="#時間帯別客層" aria-label="Permalink to &quot;時間帯別客層&quot;">​</a></h4><p>各時間帯の組数・客数・平均人数・客単価。</p><h3 id="_13-5-4-実例-週次サマリー" tabindex="-1">13.5.4 実例（週次サマリー） <a class="header-anchor" href="#_13-5-4-実例-週次サマリー" aria-label="Permalink to &quot;13.5.4 実例（週次サマリー）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>平均滞在 42 分 / 平均回転 4.2 / ピーク 19 時 / 超過率 8%</span></span>
<span class="line"><span>ランチ:   142 組 / 198 人 / 32 分 / ¥197,400</span></span>
<span class="line"><span>ディナー: 186 組 / 412 人 / 58 分 / ¥643,200</span></span></code></pre></div><p>→ ディナー 58 分は業界平均 (45-60 分) の上限。回転率向上に「90 分制」導入の余地あり。</p><hr><h2 id="_13-6-スタッフ評価レポート" tabindex="-1">13.6 スタッフ評価レポート <a class="header-anchor" href="#_13-6-スタッフ評価レポート" aria-label="Permalink to &quot;13.6 スタッフ評価レポート&quot;">​</a></h2><p>「レポート」タブ → 「スタッフ評価」サブタブ（実装: <code>staff-report.js</code>、API: <code>staff-report.php</code>）</p><h3 id="_13-6-1-操作前のチェックリスト" tabindex="-1">13.6.1 操作前のチェックリスト <a class="header-anchor" href="#_13-6-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.6.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>各スタッフが個別アカウント（共有禁止、CLAUDE.md 基本ルール）</td></tr><tr><td>2</td><td>ハンディ POS / レジ PIN を運用中</td></tr><tr><td>3</td><td>manager 以上</td></tr></tbody></table><h3 id="_13-6-2-操作手順" tabindex="-1">13.6.2 操作手順 <a class="header-anchor" href="#_13-6-2-操作手順" aria-label="Permalink to &quot;13.6.2 操作手順&quot;">​</a></h3><ol><li><strong>「レポート」</strong> → <strong>「スタッフ評価」</strong></li><li>プリセットまたは日付ピッカー</li><li><strong>「表示」</strong> ボタン</li></ol><h3 id="_13-6-3-アラートバナー-最上部" tabindex="-1">13.6.3 アラートバナー（最上部） <a class="header-anchor" href="#_13-6-3-アラートバナー-最上部" aria-label="Permalink to &quot;13.6.3 アラートバナー（最上部）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>表示</th><th>意味</th></tr></thead><tbody><tr><td>緑「異常なし」</td><td>期間内にアラートなし</td></tr><tr><td>赤「アラート N 件」</td><td>severity=danger / warning が検出</td></tr></tbody></table><p>severity=danger 例:</p><ul><li>レジ過不足が連続 3 日マイナス</li><li>同一スタッフのキャンセル率 ≥30%</li></ul><h3 id="_13-6-4-スタッフパフォーマンス一覧" tabindex="-1">13.6.4 スタッフパフォーマンス一覧 <a class="header-anchor" href="#_13-6-4-スタッフパフォーマンス一覧" aria-label="Permalink to &quot;13.6.4 スタッフパフォーマンス一覧&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>スタッフ</td><td>表示名</td></tr><tr><td>役職</td><td>オーナー / マネージャー / スタッフ</td></tr><tr><td>注文数</td><td>ハンディ POS で投入した件数</td></tr><tr><td>売上</td><td>担当注文の合計</td></tr><tr><td>客単価</td><td>売上 ÷ 注文数</td></tr><tr><td>キャンセル率</td><td>キャンセル ÷ 全注文。20% 以上は赤太字</td></tr><tr><td>満足度</td><td>お客様評価平均（評点 + 件数）。3.0 未満赤、4.0 以上緑</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">device ロールはスタッフ集計から除外</p><p>KDS / レジの端末アカウント（<code>role=&#39;device&#39;</code>）はスタッフではないため、評価レポートに含まれません。シフト管理・人件費・スタッフレポート全てから除外（CLAUDE.md「device ロール」参照）。</p></div><h3 id="_13-6-5-キャンセル分析" tabindex="-1">13.6.5 キャンセル分析 <a class="header-anchor" href="#_13-6-5-キャンセル分析" aria-label="Permalink to &quot;13.6.5 キャンセル分析&quot;">​</a></h3><ul><li>棒グラフ: スタッフ別キャンセル件数</li><li>テーブル: スタッフ × キャンセル理由（上位 5 件）</li></ul><h3 id="_13-6-6-レジ差異テーブル" tabindex="-1">13.6.6 レジ差異テーブル <a class="header-anchor" href="#_13-6-6-レジ差異テーブル" aria-label="Permalink to &quot;13.6.6 レジ差異テーブル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>日付</td><td>—</td></tr><tr><td>開店者</td><td>レジ開け担当</td></tr><tr><td>閉店者</td><td>レジ閉め担当</td></tr><tr><td>予想残高</td><td>—</td></tr><tr><td>実際残高</td><td>—</td></tr><tr><td>差異</td><td>プラス青 / マイナス赤 /</td></tr></tbody></table><h3 id="_13-6-7-深夜帯操作ログ-23-00〜05-00" tabindex="-1">13.6.7 深夜帯操作ログ（23:00〜05:00） <a class="header-anchor" href="#_13-6-7-深夜帯操作ログ-23-00〜05-00" aria-label="Permalink to &quot;13.6.7 深夜帯操作ログ（23:00〜05:00）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>日時</td><td>—</td></tr><tr><td>スタッフ</td><td>—</td></tr><tr><td>操作</td><td>注文キャンセル / 出金 / 設定変更</td></tr><tr><td>理由</td><td>—</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">深夜操作のレッドフラグ</p><ul><li>出金 ¥10,000 以上 → 必ず理由を確認</li><li>注文キャンセル → 売上隠蔽の可能性</li><li>設定変更 → 価格改ざん・PIN 変更 詳細監査は 13.10 監査ログで <code>created_at &gt;= &#39;23:00&#39;</code> で絞り込み。</li></ul></div><h3 id="_13-6-8-実例-問題スタッフ早期発見" tabindex="-1">13.6.8 実例（問題スタッフ早期発見） <a class="header-anchor" href="#_13-6-8-実例-問題スタッフ早期発見" aria-label="Permalink to &quot;13.6.8 実例（問題スタッフ早期発見）&quot;">​</a></h3><p>「佐藤」: キャンセル率 28% (赤) / 理由「お客様変更」5 件多い → 監査ログで佐藤の order_cancel を時間帯確認 → 深夜帯集中なら深夜帯操作ログ照合 → 個別面談・OJT 強化。</p><hr><h2 id="_13-7-併売分析" tabindex="-1">13.7 併売分析 <a class="header-anchor" href="#_13-7-併売分析" aria-label="Permalink to &quot;13.7 併売分析&quot;">​</a></h2><p>「レポート」タブ → 「併売分析」サブタブ（実装: <code>basket-analysis.js</code>、API: <code>basket-analysis.php</code>）</p><h3 id="_13-7-1-操作前のチェックリスト" tabindex="-1">13.7.1 操作前のチェックリスト <a class="header-anchor" href="#_13-7-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.7.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>期間内に 100 件以上の paid 注文 (推奨)</td></tr><tr><td>2</td><td>manager 以上</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">データ量が少ないと意味がない</p><p>バスケット分析は確率論。100 取引未満では偶然の組み合わせがリフト値を歪めます。月次以上の単位で実行を推奨。</p></div><h3 id="_13-7-2-操作手順" tabindex="-1">13.7.2 操作手順 <a class="header-anchor" href="#_13-7-2-操作手順" aria-label="Permalink to &quot;13.7.2 操作手順&quot;">​</a></h3><ol><li><strong>「レポート」</strong> → <strong>「併売分析」</strong></li><li>既定で「今月」が選択</li><li><strong>最小サポート</strong> ドロップダウンで閾値を選択（既定: 3 回）</li><li><strong>「表示」</strong> ボタン</li></ol><h3 id="_13-7-3-入力フィールドの詳細表" tabindex="-1">13.7.3 入力フィールドの詳細表 <a class="header-anchor" href="#_13-7-3-入力フィールドの詳細表" aria-label="Permalink to &quot;13.7.3 入力フィールドの詳細表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>既定</th><th>選択肢</th><th>補足</th></tr></thead><tbody><tr><td>1</td><td>プリセット</td><td>今月</td><td>今日/昨日/今週/今月</td><td></td></tr><tr><td>2</td><td>from</td><td>月初</td><td>YYYY-MM-DD</td><td></td></tr><tr><td>3</td><td>to</td><td>当日</td><td>YYYY-MM-DD</td><td></td></tr><tr><td>4</td><td>min_support</td><td>3</td><td>2 / 3 / 5 / 10</td><td>最低何回以上の同時注文か</td></tr></tbody></table><h3 id="_13-7-4-サマリーカード" tabindex="-1">13.7.4 サマリーカード <a class="header-anchor" href="#_13-7-4-サマリーカード" aria-label="Permalink to &quot;13.7.4 サマリーカード&quot;">​</a></h3><table tabindex="0"><thead><tr><th>カード</th><th>説明</th></tr></thead><tbody><tr><td>分析対象注文数</td><td>期間内の paid 注文件数</td></tr><tr><td>検出ペア数</td><td>min_support を満たすペア</td></tr><tr><td>品目数</td><td>ユニーク品目数</td></tr></tbody></table><h3 id="_13-7-5-併売ペアランキング" tabindex="-1">13.7.5 併売ペアランキング <a class="header-anchor" href="#_13-7-5-併売ペアランキング" aria-label="Permalink to &quot;13.7.5 併売ペアランキング&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th><th>解釈</th></tr></thead><tbody><tr><td>品目 A</td><td>—</td><td></td></tr><tr><td>品目 B</td><td>—</td><td></td></tr><tr><td>出現回数</td><td>同一注文で両方出た回数</td><td></td></tr><tr><td>確信度 (A→B)</td><td>A を注文した人の B 注文率</td><td>A の固定客の B 認知度</td></tr><tr><td>確信度 (B→A)</td><td>B を注文した人の A 注文率</td><td></td></tr><tr><td>リフト値</td><td>偶然との乖離度</td><td>1.5+ 緑 / 1.0 中立 / &lt;1.0 赤</td></tr></tbody></table><h3 id="_13-7-6-リフト値の解釈表" tabindex="-1">13.7.6 リフト値の解釈表 <a class="header-anchor" href="#_13-7-6-リフト値の解釈表" aria-label="Permalink to &quot;13.7.6 リフト値の解釈表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>リフト値</th><th>意味</th><th>アクション</th></tr></thead><tbody><tr><td>≥ 2.0</td><td>強い正の相関</td><td>セットメニュー化候補</td></tr><tr><td>1.5〜1.9</td><td>正の相関</td><td>レコメンド対象</td></tr><tr><td>1.0</td><td>無相関</td><td>偶然</td></tr><tr><td>0.5〜0.99</td><td>弱い負の相関</td><td>同時提案を避ける</td></tr><tr><td>&lt; 0.5</td><td>強い負の相関</td><td>競合関係（同価格帯の代替品）</td></tr></tbody></table><h3 id="_13-7-7-品目別出現頻度-バーチャート" tabindex="-1">13.7.7 品目別出現頻度（バーチャート） <a class="header-anchor" href="#_13-7-7-品目別出現頻度-バーチャート" aria-label="Permalink to &quot;13.7.7 品目別出現頻度（バーチャート）&quot;">​</a></h3><p>注文頻度の上位 20 品目を棒グラフで表示。</p><h3 id="_13-7-8-実例-月次-top-5" tabindex="-1">13.7.8 実例（月次 TOP 5） <a class="header-anchor" href="#_13-7-8-実例-月次-top-5" aria-label="Permalink to &quot;13.7.8 実例（月次 TOP 5）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 焼き魚定食 × 味噌汁追加  リフト 2.4 (緑、セット化候補)</span></span>
<span class="line"><span>2. 唐揚げ定食 × 卵かけ御飯  リフト 2.1 (緑)</span></span>
<span class="line"><span>3. 生ビール × 唐揚げ        リフト 1.8 (緑)</span></span>
<span class="line"><span>4. ハンバーグ × ライス大盛   リフト 1.6 (緑)</span></span>
<span class="line"><span>5. 焼き魚 × 唐揚げ定食       リフト 0.4 (赤・代替関係、同時提示回避)</span></span></code></pre></div><p>→ リフト ≥1.5 のペアはセット化 + AI ウェイター (14.5) の <code>daily_recommendations</code> に反映。</p><hr><h2 id="_13-8-abc-分析-owner-専用" tabindex="-1">13.8 ABC 分析（owner 専用） <a class="header-anchor" href="#_13-8-abc-分析-owner-専用" aria-label="Permalink to &quot;13.8 ABC 分析（owner 専用）&quot;">​</a></h2><p>owner-dashboard.html → 「ABC 分析」タブ（実装: <code>abc-analytics.js</code>、API: <code>/api/owner/analytics-abc.php</code>）</p><h3 id="_13-8-1-操作前のチェックリスト" tabindex="-1">13.8.1 操作前のチェックリスト <a class="header-anchor" href="#_13-8-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.8.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>owner ロール</td></tr><tr><td>2</td><td>期間内に売上データがある</td></tr></tbody></table><h3 id="_13-8-2-abc-分類のルール" tabindex="-1">13.8.2 ABC 分類のルール <a class="header-anchor" href="#_13-8-2-abc-分類のルール" aria-label="Permalink to &quot;13.8.2 ABC 分類のルール&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ランク</th><th>売上構成</th><th>意味</th></tr></thead><tbody><tr><td>A</td><td>上位 70%</td><td>主力商品</td></tr><tr><td>B</td><td>70〜90%</td><td>準主力</td></tr><tr><td>C</td><td>90〜100%</td><td>候補メニュー</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">比率カスタマイズ</p><p>現状 A=70 / B=20 / C=10 の固定。将来的に設定 UI を追加予定。</p></div><h3 id="_13-8-3-操作手順" tabindex="-1">13.8.3 操作手順 <a class="header-anchor" href="#_13-8-3-操作手順" aria-label="Permalink to &quot;13.8.3 操作手順&quot;">​</a></h3><ol><li>owner-dashboard.html → <strong>「ABC 分析」</strong> タブ</li><li>（owner のみ）店舗フィルタで「全店舗合算」または個別店舗を選択</li><li>プリセット（既定: 今月）</li><li><strong>「表示」</strong> ボタン</li></ol><h3 id="_13-8-4-表示セクション" tabindex="-1">13.8.4 表示セクション <a class="header-anchor" href="#_13-8-4-表示セクション" aria-label="Permalink to &quot;13.8.4 表示セクション&quot;">​</a></h3><ul><li>サマリーカード（総品目数 / 総売上 / A 数 / B 数 / C 数）</li><li>ABC 一覧テーブル（品目 × 売上 × 構成比 × 累積比 × ランク）</li><li>カテゴリ別集計（カテゴリ単位でも ABC 計算）</li><li>バーチャート（CSS only、外部ライブラリなし）</li></ul><h3 id="_13-8-5-実例-3-店舗合算" tabindex="-1">13.8.5 実例（3 店舗合算） <a class="header-anchor" href="#_13-8-5-実例-3-店舗合算" aria-label="Permalink to &quot;13.8.5 実例（3 店舗合算）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>総品目 87 / 総売上 ¥4,200,000</span></span>
<span class="line"><span>A: 12 品 (¥2,940,000、70%) — 欠品防止最優先</span></span>
<span class="line"><span>B: 21 品 (¥840,000、20%)</span></span>
<span class="line"><span>C: 54 品 (¥420,000、10%) — 提供時間 / 原価率の悪い品から廃止候補精査</span></span></code></pre></div><hr><h2 id="_13-9-クロス店舗レポート-owner-専用" tabindex="-1">13.9 クロス店舗レポート（owner 専用） <a class="header-anchor" href="#_13-9-クロス店舗レポート-owner-専用" aria-label="Permalink to &quot;13.9 クロス店舗レポート（owner 専用）&quot;">​</a></h2><p>owner-dashboard.html → 「クロス店舗レポート」タブ（<code>cross-store-report.js</code>、<code>/api/owner/cross-store-report.php</code>）</p><h3 id="_13-9-1-用途" tabindex="-1">13.9.1 用途 <a class="header-anchor" href="#_13-9-1-用途" aria-label="Permalink to &quot;13.9.1 用途&quot;">​</a></h3><p>複数店舗を運営するチェーン本部が、店舗間比較・全社合算を一画面で見るためのレポート。</p><h3 id="_13-9-2-操作手順" tabindex="-1">13.9.2 操作手順 <a class="header-anchor" href="#_13-9-2-操作手順" aria-label="Permalink to &quot;13.9.2 操作手順&quot;">​</a></h3><ol><li>owner-dashboard.html → <strong>「クロス店舗レポート」</strong> タブ</li><li>店舗フィルタ（既定: 全店舗合算）</li><li>プリセット（既定: 今日）</li><li><strong>「表示」</strong> ボタン</li></ol><h3 id="_13-9-3-サマリーカード" tabindex="-1">13.9.3 サマリーカード <a class="header-anchor" href="#_13-9-3-サマリーカード" aria-label="Permalink to &quot;13.9.3 サマリーカード&quot;">​</a></h3><table tabindex="0"><thead><tr><th>カード</th><th>説明</th></tr></thead><tbody><tr><td>売上合計</td><td>全店舗合算</td></tr><tr><td>注文合計</td><td>—</td></tr><tr><td>店舗数</td><td>アクティブ店舗</td></tr><tr><td>平均注文額</td><td>—</td></tr><tr><td>キャンセル件数</td><td>+ キャンセル率</td></tr><tr><td>キャンセル金額</td><td>赤色</td></tr></tbody></table><h3 id="_13-9-4-店舗別ランキング" tabindex="-1">13.9.4 店舗別ランキング <a class="header-anchor" href="#_13-9-4-店舗別ランキング" aria-label="Permalink to &quot;13.9.4 店舗別ランキング&quot;">​</a></h3><p>各店舗の売上・注文・客単価を表形式で並べてランキング。</p><h3 id="_13-9-5-実例-チェーン本部-1-日" tabindex="-1">13.9.5 実例（チェーン本部 1 日） <a class="header-anchor" href="#_13-9-5-実例-チェーン本部-1-日" aria-label="Permalink to &quot;13.9.5 実例（チェーン本部 1 日）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>総売上 ¥823,400 / 412 件 / 3 店舗 / ¥1,998 平均</span></span>
<span class="line"><span>渋谷 ¥412,300 (198, ¥2,082) / 新宿 ¥248,100 (132, ¥1,879) / 池袋 ¥163,000 (82, ¥1,988)</span></span></code></pre></div><p>→ 新宿は客単価が低い → メニュー戦略再検討。</p><hr><h2 id="_13-10-監査ログ画面" tabindex="-1">13.10 監査ログ画面 <a class="header-anchor" href="#_13-10-監査ログ画面" aria-label="Permalink to &quot;13.10 監査ログ画面&quot;">​</a></h2><p>dashboard.html → 「設定」グループ →「監査ログ」サブタブ（実装: <code>audit-log-viewer.js</code>、API: <code>audit-log.php</code>）。「誰が、いつ、何を操作したか」の追跡。詳細は 18 章「セキュリティ」。</p><h3 id="_13-10-1-操作前のチェックリスト" tabindex="-1">13.10.1 操作前のチェックリスト <a class="header-anchor" href="#_13-10-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.10.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>manager 以上のロール</td></tr><tr><td>2</td><td>テナント内に <code>audit_log</code> テーブルが存在する（マイグレーション済み）</td></tr></tbody></table><h3 id="_13-10-2-操作手順" tabindex="-1">13.10.2 操作手順 <a class="header-anchor" href="#_13-10-2-操作手順" aria-label="Permalink to &quot;13.10.2 操作手順&quot;">​</a></h3><ol><li>dashboard.html → <strong>「設定」</strong> グループ → <strong>「監査ログ」</strong> サブタブ</li><li>フィルタ: 期間 (from/to)、操作種別、スタッフ</li><li><strong>「検索」</strong> ボタン</li><li>テーブル表示（50 件 / ページ）+ ページネーション</li></ol><h3 id="_13-10-3-入力フィールドの詳細表" tabindex="-1">13.10.3 入力フィールドの詳細表 <a class="header-anchor" href="#_13-10-3-入力フィールドの詳細表" aria-label="Permalink to &quot;13.10.3 入力フィールドの詳細表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>既定</th><th>形式</th><th>補足</th></tr></thead><tbody><tr><td>1</td><td>from</td><td>今日</td><td>YYYY-MM-DD</td><td>00:00:00</td></tr><tr><td>2</td><td>to</td><td>今日</td><td>YYYY-MM-DD</td><td>23:59:59</td></tr><tr><td>3</td><td>action</td><td>すべて</td><td>ENUM</td><td>26 種から選択</td></tr><tr><td>4</td><td>user_id</td><td>すべて</td><td>UUID</td><td>スタッフ絞り込み</td></tr><tr><td>5</td><td>limit</td><td>50</td><td>1-200</td><td>1 ページ件数</td></tr><tr><td>6</td><td>offset</td><td>0</td><td>整数</td><td>ページネーション</td></tr></tbody></table><h3 id="_13-10-4-主な操作種別" tabindex="-1">13.10.4 主な操作種別 <a class="header-anchor" href="#_13-10-4-主な操作種別" aria-label="Permalink to &quot;13.10.4 主な操作種別&quot;">​</a></h3><p><code>menu_update</code> / <code>menu_soldout</code> / <code>staff_create</code> / <code>staff_delete</code> / <code>device_create</code> / <code>order_cancel</code> / <code>payment_complete</code> / <code>payment_refund</code> / <code>cashier_pin_used</code> / <code>cashier_pin_failed</code> / <code>register_open</code> / <code>register_close</code> / <code>cash_in</code> / <code>cash_out</code> / <code>attendance_clock_in/out</code> / <code>settings_update</code> / <code>login</code> / <code>logout</code></p><h3 id="_13-10-5-詳細フィールドの整形-cb1" tabindex="-1">13.10.5 詳細フィールドの整形（CB1） <a class="header-anchor" href="#_13-10-5-詳細フィールドの整形-cb1" aria-label="Permalink to &quot;13.10.5 詳細フィールドの整形（CB1）&quot;">​</a></h3><p>差分（旧値→新値の取消線）/ 金額 ¥1,234 / boolean ✓× / enum 日本語化 (cash→現金、device→端末) / 長い ID は先頭 8 文字省略 / tenant_id 等冗長フィールドは非表示。</p><h3 id="_13-10-6-実例-価格改ざん検出" tabindex="-1">13.10.6 実例（価格改ざん検出） <a class="header-anchor" href="#_13-10-6-実例-価格改ざん検出" aria-label="Permalink to &quot;13.10.6 実例（価格改ざん検出）&quot;">​</a></h3><p>クレーム「先週¥1,000 が今日¥1,100」→ action=メニュー変更、過去 7 日検索 → 「価格 ¥1,000 → ¥1,100」差分発見 → 担当者に意図確認。</p><h3 id="_13-10-7-ロール別閲覧範囲" tabindex="-1">13.10.7 ロール別閲覧範囲 <a class="header-anchor" href="#_13-10-7-ロール別閲覧範囲" aria-label="Permalink to &quot;13.10.7 ロール別閲覧範囲&quot;">​</a></h3><p>owner = テナント全体 / manager = 自店舗 + 自テナントレベル操作 (OR 条件) / staff = 閲覧不可。実装: <code>api/store/audit-log.php</code> L44-49。</p><hr><h2 id="_13-11-エラー監視ダッシュボード-cb1" tabindex="-1">13.11 エラー監視ダッシュボード（CB1） <a class="header-anchor" href="#_13-11-エラー監視ダッシュボード-cb1" aria-label="Permalink to &quot;13.11 エラー監視ダッシュボード（CB1）&quot;">​</a></h2><p>dashboard.html → 「設定」グループ → 「エラー監視」サブタブ（実装: <code>error-stats-viewer.js</code>、API: <code>error-stats.php</code>）。過去 N 時間に POSLA 内部で発生した API エラーを集計表示。</p><h3 id="_13-11-1-操作前のチェックリスト" tabindex="-1">13.11.1 操作前のチェックリスト <a class="header-anchor" href="#_13-11-1-操作前のチェックリスト" aria-label="Permalink to &quot;13.11.1 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>manager 以上</td></tr><tr><td>2</td><td><code>error_log</code> テーブルが存在（CB1 マイグレーション済み）</td></tr></tbody></table><h3 id="_13-11-2-操作手順" tabindex="-1">13.11.2 操作手順 <a class="header-anchor" href="#_13-11-2-操作手順" aria-label="Permalink to &quot;13.11.2 操作手順&quot;">​</a></h3><ol><li>dashboard.html → <strong>「設定」</strong> → <strong>「エラー監視」</strong></li><li><strong>期間</strong> ドロップダウン（既定: 24 時間 / 1, 6, 24, 168 から選択）</li><li><strong>再読込</strong> ボタン</li><li>サマリー（総数 / カテゴリ別 / HTTP ステータス別）+ 頻発 TOP 10 が表示</li></ol><h3 id="_13-11-3-カテゴリ別の意味" tabindex="-1">13.11.3 カテゴリ別の意味 <a class="header-anchor" href="#_13-11-3-カテゴリ別の意味" aria-label="Permalink to &quot;13.11.3 カテゴリ別の意味&quot;">​</a></h3><p>E1 システム / E2 入力検証 / E3 認証・認可 / E4 未発見 / E5 注文・KDS / E6 決済・返金 / E7 メニュー・在庫 / E8 シフト・勤怠 / E9 顧客・予約・AI</p><h3 id="_13-11-4-top-10-テーブル列" tabindex="-1">13.11.4 TOP 10 テーブル列 <a class="header-anchor" href="#_13-11-4-top-10-テーブル列" aria-label="Permalink to &quot;13.11.4 TOP 10 テーブル列&quot;">​</a></h3><p>番号 (errorNo、クリックでカタログジャンプ) / コード / HTTP / メッセージ / 件数 (≥10 で赤太字) / 最終発生</p><h3 id="_13-11-5-エラーカタログ連携" tabindex="-1">13.11.5 エラーカタログ連携 <a class="header-anchor" href="#_13-11-5-エラーカタログ連携" aria-label="Permalink to &quot;13.11.5 エラーカタログ連携&quot;">​</a></h3><p><code>Exxxx</code> をクリック → <code>docs-tenant/tenant/99-error-catalog.html#exxxx</code> が別タブで開く。AI ヘルプデスク (14.6) に「<code>E3024 とは？</code>」と直接質問も可能。</p><h3 id="_13-11-6-実例-pin-失敗急増" tabindex="-1">13.11.6 実例（PIN 失敗急増） <a class="header-anchor" href="#_13-11-6-実例-pin-失敗急増" aria-label="Permalink to &quot;13.11.6 実例（PIN 失敗急増）&quot;">​</a></h3><p>24h で E3024 INVALID_PIN が 58 件 → ブルートフォース疑い → 18.Z でレートリミット確認 + IP ブロック検討。</p><hr><h2 id="_13-12-予約レポート-l-9" tabindex="-1">13.12 予約レポート（L-9） <a class="header-anchor" href="#_13-12-予約レポート-l-9" aria-label="Permalink to &quot;13.12 予約レポート（L-9）&quot;">​</a></h2><p>2026-04-18 に追加された予約管理機能のレポート。詳細は <a href="./24-reservations.html">24 章</a> の 24.10。</p><h3 id="_13-12-1-主要指標" tabindex="-1">13.12.1 主要指標 <a class="header-anchor" href="#_13-12-1-主要指標" aria-label="Permalink to &quot;13.12.1 主要指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>予約総数</td><td>期間内の予約件数</td></tr><tr><td>来店人数</td><td>合計人数</td></tr><tr><td>no-show 率</td><td>来店なし ÷ 全予約</td></tr><tr><td>キャンセル率</td><td>キャンセル ÷ 全予約</td></tr><tr><td>ソース別</td><td>web / 電話 / walk-in / AI</td></tr><tr><td>日別件数推移</td><td>バーチャート</td></tr><tr><td>時間帯別ヒート</td><td>19 時帯が多い等</td></tr><tr><td>曜日別件数</td><td>金土が多い等</td></tr></tbody></table><h3 id="_13-12-2-no-show-率の業界目安" tabindex="-1">13.12.2 no-show 率の業界目安 <a class="header-anchor" href="#_13-12-2-no-show-率の業界目安" aria-label="Permalink to &quot;13.12.2 no-show 率の業界目安&quot;">​</a></h3><table tabindex="0"><thead><tr><th>率</th><th>評価</th><th>対策</th></tr></thead><tbody><tr><td>0〜3%</td><td>優秀</td><td>維持</td></tr><tr><td>3〜5%</td><td>一般的</td><td>前日リマインド徹底</td></tr><tr><td>5〜10%</td><td>要改善</td><td>リマインド + 直前確認</td></tr><tr><td>10% 超</td><td>危険</td><td>予約金（デポジット）導入検討</td></tr></tbody></table><hr><h2 id="_13-y-faq-25-件" tabindex="-1">13.Y FAQ 25 件 <a class="header-anchor" href="#_13-y-faq-25-件" aria-label="Permalink to &quot;13.Y FAQ 25 件&quot;">​</a></h2><p><strong>Q1.</strong> 売上が会計伝票と合わない → 営業日区切り時刻 (設定 &gt; 営業日) を確認。<code>api/lib/business-day.php</code>。</p><p><strong>Q2.</strong> 過去データはいつまで → 全期間保存。削除機能なし。</p><p><strong>Q3.</strong> CSV が文字化け → Excel「データ → テキストファイル → UTF-8」。最新 Excel は BOM 自動認識。</p><p><strong>Q4.</strong> ABC 比率 (70/20/10) を変えたい → 現状固定。Phase 2 で設定 UI 予定。</p><p><strong>Q5.</strong> スタッフ評価の基準 → 注文 + 売上 + キャンセル率 + 満足度 + 出勤の総合（<code>staff-report.php</code> 参照）。</p><p><strong>Q6.</strong> クロス店舗 vs 通常レポート → クロス = 複数店舗比較 (owner)。通常 = 単一店舗詳細 (manager+)。</p><p><strong>Q7.</strong> リアルタイム売上 → 即時反映（キャッシュなし）。「表示」で都度再取得。</p><p><strong>Q8.</strong> スマレジ連携 → 現状不可。POSLA 単独運用。</p><p><strong>Q9.</strong> グラフ画像 DL → 現状テーブル / CSS バー。Phase 2 で Chart.js 予定。</p><p><strong>Q10.</strong> 予約 no-show 業界水準 → 3-5%。10% 超は予約金導入検討。</p><p><strong>Q11.</strong> カスタムレポート → 不可。CSV → Excel ピボット推奨。</p><p><strong>Q12.</strong> staff にレポート権限 → 不可。manager 以上のみ。</p><p><strong>Q13.</strong> 月次定期メール → Phase 2 予定。現状は手動 CSV → 外部ツール。</p><p><strong>Q14.</strong> バスケット分析の最小データ量 → 100 取引以上が目安。</p><p><strong>Q15.</strong> AI 分析と通常レポートの違い → レポート = 数値。AI = Gemini が文章で解釈・提案 (14 章)。</p><p><strong>Q16.</strong> device ロールはレポートに出る → スタッフ評価から除外。監査ログ・注文履歴には記録。</p><p><strong>Q17.</strong> 監査ログが重い → 期間 + 操作種別で必ず絞り込む。owner は 1 日単位推奨。</p><p><strong>Q18.</strong> エラー監視「未作成」 → CB1 マイグレーション未実行。POSLA 運営連絡。</p><p><strong>Q19.</strong> 過不足が常にプラス → 釣り銭戻し忘れ / 過剰受領。スタッフ評価で傾向確認。</p><p><strong>Q20.</strong> 提供時間が異常に長い → 注文履歴で個別確認。<code>served_at</code> 押し忘れも含む。</p><p><strong>Q21.</strong> 平均滞在が極端に長い → table_sessions が <code>session_end</code> 未設定。25 章参照。</p><p><strong>Q22.</strong> バスケットでペア 0 件 → min_support を 2 に下げる or 期間を四半期に拡大。</p><p><strong>Q23.</strong> ABC 合算と個別で結果違う → 合算では主力品が薄まる。経営=合算 / 店舗運営=個別。</p><p><strong>Q24.</strong> クロス店舗の「キャンセル」項目 → 2026-04 以降の追加。金額 / 件数 / 率を可視化。</p><p><strong>Q25.</strong> 監査ログ device_create が増えている → P1a の正常動作。新規 KDS / レジ追加で発生。</p><hr><h2 id="_13-z-トラブルシューティング表" tabindex="-1">13.Z トラブルシューティング表 <a class="header-anchor" href="#_13-z-トラブルシューティング表" aria-label="Permalink to &quot;13.Z トラブルシューティング表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>レポートが表示されない</td><td>期間にデータなし</td><td>期間を広げる / 別店舗に切替</td></tr><tr><td>数字が 0 のまま</td><td>キャンセル注文のみ / status=&#39;paid&#39; なし</td><td>注文履歴で <code>paid</code> 件数を確認</td></tr><tr><td>CSV が文字化け</td><td>文字コード不一致</td><td>UTF-8 with BOM で開く</td></tr><tr><td>売上が重複している</td><td>返金処理の二重計算（旧バグ）</td><td>最新版を確認、refund 後の正味額で表示される</td></tr><tr><td>グラフが崩れる</td><td>ブラウザ幅不足 / Safari</td><td>Chrome 全画面で表示</td></tr><tr><td>ABC 分析タブが出ない</td><td>owner ロールでない</td><td>owner で再ログイン</td></tr><tr><td>クロス店舗レポート空白</td><td>店舗が 1 店のみ</td><td>比較は 2 店以上で意味を持つ</td></tr><tr><td>監査ログが空</td><td>テーブル未作成 / フィルタ厳しすぎ</td><td>フィルタを「すべて」に</td></tr><tr><td>エラー監視「未作成」</td><td>error_log マイグ未実行</td><td>POSLA 運営連絡</td></tr><tr><td>提供時間が異常</td><td>served_at 未打刻</td><td>KDS 側で「提供完了」ボタン押し忘れ</td></tr><tr><td>過不足が毎日マイナス</td><td>レジ操作ミス / 不正の可能性</td><td>スタッフ評価レポート 13.6 → 18 章 PIN 強化</td></tr><tr><td>期間プリセットが反応しない</td><td>JS エラー</td><td>F12 コンソール確認 → POSLA 運営連絡</td></tr><tr><td>ページネーションが効かない</td><td>API 側の total / page 不整合</td><td>F12 Network タブで limit/offset 確認</td></tr><tr><td>バスケット分析が極端に遅い</td><td>取引数 10000+</td><td>期間を月単位に短縮</td></tr><tr><td>「店舗を選択してください」が出る</td><td>StoreSelector 未初期化</td><td>ページ再読込</td></tr></tbody></table><hr><h2 id="_13-w-データベース構造-posla-運営向け" tabindex="-1">13.W データベース構造（POSLA 運営向け） <a class="header-anchor" href="#_13-w-データベース構造-posla-運営向け" aria-label="Permalink to &quot;13.W データベース構造（POSLA 運営向け）&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">通常テナントは読まなくて OK</p><p>主要テーブル: <code>orders</code> / <code>order_items</code> / <code>payments</code> / <code>refunds</code> (C-R1) / <code>cash_log</code> / <code>customer_segments</code> (N-5) / <code>staff_evaluations</code> (M-1) / <code>basket_analysis_cache</code> (M-4) / <code>daily_recommendations</code> (N-1) / <code>audit_log</code> (S-2) / <code>error_log</code> (CB1) / <code>monitor_events</code> (CB1) / <code>table_sessions</code> / <code>reservations</code> (L-9)</p><h3 id="api-一覧-manager-以上" tabindex="-1">API 一覧（manager 以上） <a class="header-anchor" href="#api-一覧-manager-以上" aria-label="Permalink to &quot;API 一覧（manager 以上）&quot;">​</a></h3><p><code>GET /api/store/{sales-report,register-report,order-history,turnover-report,staff-report,basket-analysis,audit-log,error-stats,demand-forecast-data,reservation-stats}.php</code></p><h3 id="owner-専用" tabindex="-1">owner 専用 <a class="header-anchor" href="#owner-専用" aria-label="Permalink to &quot;owner 専用&quot;">​</a></h3><p><code>GET /api/owner/{cross-store-report,analytics-abc,shift/unified-view}.php</code></p><h3 id="フロント-js" tabindex="-1">フロント JS <a class="header-anchor" href="#フロント-js" aria-label="Permalink to &quot;フロント JS&quot;">​</a></h3><p><code>public/admin/js/{sales-report,register-report,order-history,turnover-report,staff-report,basket-analysis,audit-log-viewer,error-stats-viewer,abc-analytics,cross-store-report}.js</code></p><h3 id="共通ユーティリティ" tabindex="-1">共通ユーティリティ <a class="header-anchor" href="#共通ユーティリティ" aria-label="Permalink to &quot;共通ユーティリティ&quot;">​</a></h3><ul><li><code>api/lib/business-day.php</code> の <code>get_business_day_range()</code> — 営業日区切り時刻を考慮した期間変換</li><li><code>Utils.getPresetRange(&#39;today&#39;|&#39;yesterday&#39;|&#39;week&#39;|&#39;month&#39;)</code> — フロント側のプリセット</li><li><code>Utils.formatYen()</code> / <code>formatDuration()</code> / <code>escapeHtml()</code> — 表示整形</li></ul><p>CSV: 各 API に <code>?format=csv</code> （一部未実装、運営で grep 確認）</p></div><hr><h2 id="関連章" tabindex="-1">関連章 <a class="header-anchor" href="#関連章" aria-label="Permalink to &quot;関連章&quot;">​</a></h2><ul><li><a href="./14-ai.html">14. AI アシスタント</a> — レポート結果を AI で分析・SNS 投稿生成</li><li><a href="./15-owner.html">15. オーナーダッシュボード</a> — クロス店舗・ABC・本部運営</li><li><a href="./18-security.html">18. セキュリティとアカウント管理</a> — 監査ログ・エラー監視の詳細</li><li><a href="./24-reservations.html">24. 予約管理</a> — 予約レポート（L-9）</li></ul><hr><h2 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h2><ul><li><strong>以前</strong>: 基本機能 (264 行)</li><li><strong>2026-04-18</strong>: フル粒度化、予約レポート (L-9) + FAQ + トラブル + 技術補足 追加</li><li><strong>2026-04-19</strong>: Phase B Batch-9 — 共通操作・操作前チェックリスト・画面遷移 ASCII・実例・監査ログ画面・エラー監視ダッシュボード・ABC・クロス店舗 各章を追加し、FAQ を 25 件に拡充</li></ul>`,264)])])}const u=d(o,[["render",h]]);export{p as __pageData,u as default};
